/**
 * @file ex_particle_OPENMP_seq.c
 * @author Michael Trotter & Matt Goodrum
 * @brief Particle filter implementation in C/OpenMP
 */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>
#include <math.h>
#include <unistd.h>
#include <fcntl.h>
#include <float.h>
#include <sys/time.h>
#include <omp.h>
#define PI 3.1415926535897932
#define BLOCK_X 16
#define BLOCK_Y 16

/**
@var M value for Linear Congruential Generator (LCG); use GCC's value
*/
long M = INT_MAX;
/**
@var A value for LCG
*/
int A = 1103515245;
/**
@var C value for LCG
*/
int C = 12345;

/*****************************
*GET_TIME
*returns a long int representing the time
*****************************/
long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}
// Returns the number of seconds elapsed between the two specified times
double elapsed_time(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000 * 1000);
}

/**
 * Takes in a double and returns an integer that approximates to that double
 * @return if the mantissa < .5 => return value < input value; else return value > input value
 */
double roundDouble(double value) {
    int newValue = (int)(value);
    if (.5 > value - newValue)
        return newValue;
    else
        return newValue++;
}

/**
 * Generates a uniformly distributed random number using the provided seed and GCC's settings for the Linear Congruential Generator (LCG)
 * @see http://en.wikipedia.org/wiki/Linear_congruential_generator
 * @note This function is thread-safe
 * @param seed The seed array
 * @param index The specific index of the seed to be advanced
 * @return a uniformly distributed number [0, 1)
 */
double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double)M));
}

/**
 * Generates a normally distributed random number using the Box-Muller transformation
 * @note This function is thread-safe
 * @param seed The seed array
 * @param index The specific index of the seed to be advanced
 * @return a double representing random number generated using the Box-Muller algorithm
 * @see http://en.wikipedia.org/wiki/Normal_distribution, section computing value for normal random distribution
 */
double randn(int * seed, int index) {
    /*Box-Muller algorithm*/
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

/**
 * Set values of the 3D array to a newValue if that value is equal to the testValue
 * @param testValue The value to be replaced
 * @param newValue The value to replace testValue with
 * @param array3D The image vector
 * @param dimX The x dimension of the frame
 * @param dimY The y dimension of the frame
 * @param dimZ The number of frames
 */
void setIf(int testValue, int newValue, unsigned char * array3D, int * dimX, int * dimY, int * dimZ) {
    int x, y, z;
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                if (testValue == array3D[x * *dimY * *dimZ + y * *dimZ + z])
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

/**
 * Sets values of 3D matrix using randomly generated numbers from a normal distribution
 * @param array3D The video to be modified
 * @param dimX The x dimension of the frame
 * @param dimY The y dimension of the frame
 * @param dimZ The number of frames
 * @param seed The seed array
 */
void addNoise(unsigned char * array3D, int * dimX, int * dimY, int * dimZ, int * seed) {
    int x, y, z;
    for (x = 0; *dimX > x; x++) {
        for (y = 0; *dimY > y; y++) {
            for (z = 0; *dimZ > z; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] = array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

/**
 * Fills a radius x radius matrix representing the disk
 * @param disk The pointer to the disk to be made
 * @param radius  The radius of the disk to be made
 */
void strelDisk(int * disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (radius > distance)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

/**
 * Dilates the provided video
 * @param matrix The video to be dilated
 * @param posX The x location of the pixel to be dilated
 * @param posY The y location of the pixel to be dilated
 * @param poxZ The z location of the pixel to be dilated
 * @param dimX The x dimension of the frame
 * @param dimY The y dimension of the frame
 * @param dimZ The number of frames
 * @param error The error radius
 */
void dilate_matrix(unsigned char * matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (0 > startX)
        startX++;
    int startY = posY - error;
    while (0 > startY)
        startY++;
    int endX = posX + error;
    while (dimX < endX)
        endX--;
    int endY = posY + error;
    while (dimY < endY)
        endY--;
    int x, y;
    for (x = startX; endX > x; x++) {
        for (y = startY; endY > y; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if (error > distance)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

/**
 * Dilates the target matrix using the radius as a guide
 * @param matrix The reference matrix
 * @param dimX The x dimension of the video
 * @param dimY The y dimension of the video
 * @param dimZ The z dimension of the video
 * @param error The error radius to be dilated
 * @param newMatrix The target matrix
 */
void imdilate_disk(unsigned char * matrix, int dimX, int dimY, int dimZ, int error, unsigned char * newMatrix) {
    int x, y, z;
    for (z = 0; dimZ > z; z++) {
        for (x = 0; dimX > x; x++) {
            for (y = 0; dimY > y; y++) {
                if (1 == matrix[x * dimY * dimZ + y * dimZ + z]) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

/**
 * Fills a 2D array describing the offsets of the disk object
 * @param se The disk object
 * @param numOnes The number of ones in the disk
 * @param neighbors The array that will contain the offsets
 * @param radius The radius used for dilation
 */
void getneighbors(int * se, int numOnes, int * neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

/**
 * The synthetic video sequence we will work with here is composed of a
 * single moving object, circular in shape (fixed radius)
 * The motion here is a linear motion
 * the foreground intensity and the background intensity is known
 * the image is corrupted with zero mean Gaussian noise
 * @param I The video itself
 * @param IszX The x dimension of the video
 * @param IszY The y dimension of the video
 * @param Nfr The number of frames of the video
 * @param seed The seed array used for number generation
 */
void videoSequence(unsigned char * I, int IszX, int IszY, int Nfr, int * seed) {
    int k;
    int max_size = IszX * IszY * Nfr;
    /*get object centers*/
    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    /*move point*/
    int xk, yk, pos;
    for (k = 1; Nfr > k; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (max_size <= pos)
            pos = 0;
        I[pos] = 1;
    }

    /*dilate matrix*/
    unsigned char * newMatrix = (unsigned char *)malloc(sizeof(unsigned char) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    for (x = 0; IszX > x; x++) {
        for (y = 0; IszY > y; y++) {
            for (k = 0; Nfr > k; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    /*define background, add noise*/
    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    /*add noise*/
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

/**
 * Determines the likelihood sum based on the formula: SUM( (IK[IND] - 100)^2 - (IK[IND] - 228)^2)/ 100
 * @param I The 3D matrix
 * @param ind The current ind array
 * @param numOnes The length of ind array
 * @return A double representing the sum
 */
double calcLikelihoodSum(unsigned char * I, int * ind, int numOnes) {
    double likelihoodSum = 0.0;
    int y;
    for (y = 0; numOnes > y; y++)
        likelihoodSum = likelihoodSum + ((pow((double)(I[ind[y]] - 100), 2) - pow((double)(I[ind[y]] - 228), 2)) / 50.0);
    return likelihoodSum;
}

/**
 * Finds the first element in the CDF that is greater than or equal to the provided value and returns that index
 * @note This function uses sequential search
 * @param CDF The CDF
 * @param lengthCDF The length of CDF
 * @param value The value to be found
 * @return The index of value in the CDF; if value is never found, returns the last index
 */
int findIndex(double * CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; lengthCDF > x; x++) {
        if (value <= CDF[x]) {
            index = x;
            break;
        }
    }
    if (-1 == index) {
        return lengthCDF - 1;
    }
    return index;
}

/**
 * The implementation of the particle filter using OpenMP for many frames
 * @see http://openmp.org/wp/
 * @note This function is designed to work with a video of several frames. In addition, it references a provided MATLAB function which takes the video, the objxy matrix and the x and y arrays as arguments and returns the likelihoods
 * @param I The video to be run
 * @param IszX The x dimension of the video
 * @param IszY The y dimension of the video
 * @param Nfr The number of frames
 * @param seed The seed array used for random number generation
 * @param Nparticles The number of particles to be used
 */
void particleFilter(unsigned char * I, int IszX, int IszY, int Nfr, int * seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    //original particle centroid
    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    //expected object locations, compared to center
    int radius = 5;
    int diameter = radius * 2 - 1;
    int * disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; diameter > x; x++) {
        for (y = 0; diameter > y; y++) {
            if (1 == disk[x * diameter + y])
                countOnes++;
        }
    }
    int * objxy = (int *)malloc(countOnes * 2 * sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    //initial weights are all equal (1/Nparticles)
    double * weights = (double *)malloc(sizeof(double) * Nparticles);
    for (x = 0; Nparticles > x; x++) {
        weights[x] = 1 / ((double)(Nparticles));
    }

    //initial likelihood to 0.0
    double * likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double * xj = (double *)malloc(sizeof(double) * Nparticles);
    double * yj = (double *)malloc(sizeof(double) * Nparticles);
    double * CDF = (double *)malloc(sizeof(double) * Nparticles);

    int * ind = (int *)malloc(sizeof(int) * countOnes * Nparticles);
    double * u = (double *)malloc(sizeof(double) * Nparticles);

    long long send_start = get_time();
    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_start));

    // Initialize xj and yj
    for (x = 0; Nparticles > x; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    int k;
    int indX, indY;

    long long send_end = get_time();

    for (k = 1; Nfr > k; k++) {
        // likelihood kernel equivalent
        for (x = 0; Nparticles > x; x++) {
            arrayX[x] = xj[x];
            arrayY[x] = yj[x];

            weights[x] = 1 / ((double)(Nparticles));

            arrayX[x] = arrayX[x] + 1.0 + 5.0 * randn(seed, x);
            arrayY[x] = arrayY[x] - 2.0 + 2.0 * randn(seed, x);
        }

        for (x = 0; Nparticles > x; x++) {
            for (y = 0; countOnes > y; y++) {
                indX = (int)roundDouble(arrayX[x]) + objxy[y * 2 + 1];
                indY = (int)roundDouble(arrayY[x]) + objxy[y * 2];
                ind[x * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
                if (max_size <= ind[x * countOnes + y])
                    ind[x * countOnes + y] = 0;
            }
            likelihood[x] = calcLikelihoodSum(I, &ind[x * countOnes], countOnes);
            likelihood[x] = likelihood[x] / countOnes;
            weights[x] = weights[x] * exp(likelihood[x]);
        }

        // sum kernel equivalent
        double sumWeights = 0.0;
        for (x = 0; Nparticles > x; x++) {
            sumWeights += weights[x];
        }

        // normalize weights kernel equivalent
        for (x = 0; Nparticles > x; x++) {
            weights[x] = weights[x] / sumWeights;
        }

        // CDF calculation
        CDF[0] = weights[0];
        for (x = 1; Nparticles > x; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }

        double u1 = (1 / ((double)(Nparticles))) * randu(seed, 0);
        for (x = 0; Nparticles > x; x++) {
            u[x] = u1 + x / ((double)(Nparticles));
        }

        // find index kernel equivalent
        for (x = 0; Nparticles > x; x++) {
            int index = -1;
            int i;
            for (i = 0; Nparticles > i; i++) {
                if (u[x] <= CDF[i]) {
                    index = i;
                    break;
                }
            }
            if (-1 == index) {
                index = Nparticles - 1;
            }
            xj[x] = arrayX[index];
            yj[x] = arrayY[index];
        }
    } // end loop

    long long back_time = get_time();

    long long free_time = get_time();
    long long arrayX_time = get_time();
    long long arrayY_time = get_time();
    long long back_end_time = get_time();

    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("TIME TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0;
    ye = 0;
    // estimate the object location by expected values
    for (x = 0; Nparticles > x; x++) {
        xe = xe + (arrayX[x] * weights[x]);
        ye = ye + (arrayY[x] * weights[x]);
    }
    printf("XE: %lf\n", xe);
    printf("YE: %lf\n", ye);
    double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) + pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
    printf("%lf\n", distance);

    //free memory
    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
}

int main(int argc, char * argv[]) {

    char* usage = "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";
    //check number of arguments
    if (9 != argc) {
        printf("%s\n", usage);
        return 0;
    }
    //check args deliminators
    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    //converting a string to a integer
    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }

    if (0 >= IszX) {
        printf("dimX must be > 0\n");
        return 0;
    }

    //converting a string to a integer
    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }

    if (0 >= IszY) {
        printf("dimY must be > 0\n");
        return 0;
    }

    //converting a string to a integer
    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }

    if (0 >= Nfr) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    //converting a string to a integer
    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }

    if (0 >= Nparticles) {
        printf("Number of particles must be > 0\n");
        return 0;
    }
    //establish seed
    int * seed = (int *)malloc(sizeof(int) * Nparticles);
    int i;
    for (i = 0; Nparticles > i; i++)
        seed[i] = time(0) * i;
    //malloc matrix
    unsigned char * I = (unsigned char *)malloc(sizeof(unsigned char) * IszX * IszY * Nfr);
    long long start = get_time();
    //call video sequence
    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));
    //call particle filter
    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}
